import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class SecureServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");
        String encodedUserInput = encodeForHtml(userInput); // Properly encode user input

        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<body>");
        out.println("<h1>" + encodedUserInput + "</h1>"); // Display properly encoded user input
        out.println("</body>");
        out.println("</html>");
    }

    private String encodeForHtml(String input) {
        // Implement proper encoding for HTML content to prevent XSS attacks
        return input
            .replace("&", "&amp;")
            .replace("<", "&lt;")
            .replace(">", "&gt;")
            .replace("\"", "&quot;")
            .replace("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
